  howItWorks: [
    {
      id: 1,
      step: 1,
      title: 'Open the App',
      description: 'Download Falcon Ride and create your account in seconds'
    },
    {
      id: 2,
      step: 2,
      title: 'Request a Ride',
      description: 'Enter your destination and instantly see available drivers'
    },
    {
      id: 3,
      step: 3,
      title: 'Enjoy Your Ride',
      description: 'Sit back and relax while we handle the rest'
    }
  ],

  // Features / Why Choose Us
  features: [
    {
      id: 1,
      icon: 'DollarSign',
      title: 'Affordable Pricing',
      description: 'Competitive rates with no hidden fees. Pay only what you ride.'
    },
    {
      id: 2,
      icon: 'Users',
      title: 'Professional Drivers',
      description: 'Vetted, experienced drivers dedicated to your safety and comfort'
    },
    {
      id: 3,
      icon: 'Zap',
      title: 'Fast & Reliable',
      description: 'Quick pickup times and reliable service you can count on'
    },
    {
      id: 4,
      icon: 'Shield',
      title: 'Your Safety & Security',
      description: 'Advanced safety features and 24/7 support at your fingertips'
    },
    {
      id: 5,
      icon: 'Clock',
      title: 'Available 24/7',
      description: 'Rides whenever you need them, morning, noon, or night'
    },
    {
      id: 6,
      icon: 'CreditCard',
      title: 'Easy Payment',
      description: 'Multiple payment options for your convenience'
    }
  ],

  // Driver Benefits
  driverBenefits: [
    {
      id: 1,
      icon: 'Wallet',
      title: 'Earn More',
      description: 'Competitive rates and performance bonuses'
    },
    {
      id: 2,
      icon: 'TrendingUp',
      title: 'Flexible Schedule',
      description: 'Be your own boss and set your own hours'
    },
    {
      id: 3,
      icon: 'Calendar',
      title: 'No Minimum Shifts',
      description: 'Drive whenever you want, for as long as you want'
    },
    {
      id: 4,
      icon: 'Shield',
      title: 'Driver Support',
      description: '24/7 customer support dedicated to your success'
    }
  ],

  // Testimonials
  testimonials: [
    {
      id: 1,
      name: 'Sarah Johnson',
      role: 'Rider',
      rating: 5,
      comment: 'Falcon Ride is the best! Clean cars, professional drivers, and great prices.',
      avatar: 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=96&h=96&fit=crop'
    },
    {
      id: 2,
      name: 'Mike Chen',
      role: 'Driver',
      rating: 5,
      comment: 'Great flexibility and the support team is always helpful. Love working with Falcon Ride!',
      avatar: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=96&h=96&fit=crop'
    },
    {
      id: 3,
      name: 'Emily Rodriguez',
      role: 'Rider',
      rating: 5,
      comment: 'I feel safe every time. The app is easy to use and the drivers are always friendly.',
      avatar: 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=96&h=96&fit=crop'
    }
  ],

  // Cities We Serve
  cities: [
    'Toronto',
    'Mississauga',
    'Brampton',
    'Sudbury',
    'Ottawa',
    'Hamilton'
  ],

