  faqData: [
    {
      id: 1,
      question: 'How do I request a ride?',
      answer: 'Open the Falcon Ride app, enter your destination in the pickup location, confirm the pickup location, and request a ride. You\'ll see real-time driver information and estimated arrival time.'
    },
    {
      id: 2,
      question: 'How are fares calculated?',
      answer: 'Fares are calculated based on distance, time, and current demand. You\'ll always see the estimated fare before confirming your ride. There are no hidden charges.'
    },
    {
      id: 3,
      question: 'Are Falcon Ride drivers insured?',
      answer: 'Yes, all Falcon Ride drivers are fully insured including commercial insurance which provides additional coverage for passengers. Your safety is our top priority.'
    },
    {
      id: 4,
      question: 'Can I schedule rides in advance?',
      answer: 'Yes! You can schedule rides up to 30 days in advance. Simply select your preferred date and time in the app and we\'ll ensure a driver is available.'
    },
    {
      id: 5,
      question: 'What payment methods are accepted?',
      answer: 'We accept credit cards, debit cards, digital wallets, and cash. You can link your payment method in the app for quick and easy transactions.'
    },
    {
      id: 6,
      question: 'How do I become a driver?',
      answer: 'Visit our driver registration page or download the app and select "Drive with Falcon". You\'ll need a valid license, insurance, and vehicle inspection. Most approvals take 48-72 hours.'
    }
  ],

  // App Features (for RiderApp page)
  appFeatures: [
    {
      id: 1,
      icon: 'MapPin',
      title: 'Real-time Tracking',
      description: 'Track your driver\'s location in real-time with live GPS'
    },
